-- ============================================================================
-- Quiz Seed: Revelation — Part 1 (Chapters 1–11)
-- 3 difficulties × 11 chapters = 176 total questions
--   kids:   3 per chapter  = 33
--   teens:  5 per chapter  = 55
--   adults: 8 per chapter  = 88
-- ============================================================================

-- ═══════════════ CHAPTERS 1–5 ═══════════════

-- ═══ Revelation Chapter 1 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Revelation', 1, 'kids', 1, 'Who gave John this special vision?', 'Jesus Christ — God gave it to Him to show His servants things that must shortly come to pass', 'An angel named Michael', 'Moses from heaven', 'John dreamed it up himself', 'a', 'Revelation 1:1 — "The Revelation of Jesus Christ, which God gave unto him, to shew unto his servants things which must shortly come to pass."'),
('Revelation', 1, 'kids', 2, 'Where was John when he received this vision?', 'On the isle of Patmos, because he had been preaching God''s word', 'In Jerusalem at the temple', 'In Rome at a palace', 'In his house at home', 'a', 'Revelation 1:9 — "I John... was in the isle that is called Patmos, for the word of God, and for the testimony of Jesus Christ."'),
('Revelation', 1, 'kids', 3, 'What did Jesus look like when John saw Him?', 'His hair was white like wool, His eyes like fire, His feet like brass, and His voice like many waters', 'He looked like an ordinary man', 'He was invisible', 'He was very small and quiet', 'a', 'Revelation 1:14-15 — "His head and his hairs were white like wool, as white as snow; and his eyes were as a flame of fire; And his feet like unto fine brass... and his voice as the sound of many waters."'),
-- Teens
('Revelation', 1, 'teens', 1, 'What blessing is promised to those who read and hear this prophecy?', '"Blessed is he that readeth, and they that hear the words of this prophecy, and keep those things which are written therein"', 'They will become wealthy', 'They will never face trouble', 'They will gain political power', 'a', 'Revelation 1:3 — "Blessed is he that readeth, and they that hear the words of this prophecy, and keep those things which are written therein: for the time is at hand."'),
('Revelation', 1, 'teens', 2, 'What does Jesus call Himself regarding time?', 'Alpha and Omega, the beginning and the ending, which is, and which was, and which is to come, the Almighty', 'The greatest teacher', 'The king of Israel only', 'A prophet from Nazareth', 'a', 'Revelation 1:8 — "I am Alpha and Omega, the beginning and the ending, saith the Lord, which is, and which was, and which is to come, the Almighty."'),
('Revelation', 1, 'teens', 3, 'What did John see among the seven candlesticks?', 'One like unto the Son of man, clothed with a garment down to the foot and girt about with a golden girdle', 'Seven literal candles burning', 'A group of angels singing', 'Moses and Elijah standing', 'a', 'Revelation 1:13 — "And in the midst of the seven candlesticks one like unto the Son of man, clothed with a garment down to the foot, and girt about the paps with a golden girdle."'),
('Revelation', 1, 'teens', 4, 'What do the seven candlesticks represent?', 'The seven churches', 'Seven days of creation', 'Seven heavenly angels', 'Seven Old Testament prophets', 'a', 'Revelation 1:20 — "The seven candlesticks which thou sawest are the seven churches."'),
('Revelation', 1, 'teens', 5, 'What did Jesus tell John after He appeared to him?', '"Fear not; I am the first and the last: I am he that liveth, and was dead; and, behold, I am alive for evermore"', '"Run away and hide"', '"Tell no one what you have seen"', '"Go back to Jerusalem"', 'a', 'Revelation 1:17-18 — "Fear not; I am the first and the last: I am he that liveth, and was dead; and, behold, I am alive for evermore, Amen; and have the keys of hell and of death."'),
-- Adults
('Revelation', 1, 'adults', 1, 'What is the literary genre and purpose of the book as stated in verse 1?', 'An apokalypsis (unveiling) of Jesus Christ — God gave it to Christ to show His servants things that must shortly come to pass; it is both revelation (unveiling) and prophecy (1:3)', 'A historical chronicle', 'A personal memoir', 'A collection of hymns', 'a', 'Revelation 1:1 — "The Revelation (apokalypsis) of Jesus Christ, which God gave unto him." The genitive "of Jesus Christ" is both subjective (Christ reveals) and objective (Christ is revealed).'),
('Revelation', 1, 'adults', 2, 'What does the doxology in verses 5-6 reveal about Christ''s threefold work?', 'He loved us, washed us from our sins in His own blood, and made us kings and priests unto God — combining redemption, cleansing, and royal-priestly investiture', 'He only taught moral lessons', 'He established a political kingdom', 'He was only a prophet', 'a', 'Revelation 1:5-6 — "Unto him that loved us, and washed us from our sins in his own blood, And hath made us kings and priests unto God and his Father." The threefold work echoes Exodus 19:6 — Israel''s vocation now fulfilled in the church.'),
('Revelation', 1, 'adults', 3, 'How does "every eye shall see him, and they also which pierced him" combine Old Testament sources?', 'It merges Daniel 7:13 (the Son of man coming with clouds) with Zechariah 12:10 (looking upon Him whom they pierced) — combining glory and grief, triumph and mourning', 'It quotes only Isaiah', 'It has no Old Testament background', 'It is from Psalm 22 alone', 'a', 'Revelation 1:7 — "Behold, he cometh with clouds; and every eye shall see him, and they also which pierced him: and all kindreds of the earth shall wail because of him." Daniel 7:13 + Zechariah 12:10 are fused into a single christological statement.'),
('Revelation', 1, 'adults', 4, 'What is the significance of Christ holding the seven stars in His right hand?', 'The seven stars are the angels (messengers) of the seven churches — Christ''s right hand signifies authority, protection, and sovereign control over His churches and their leadership', 'The stars are literal astronomical objects', 'It is merely decorative imagery', 'The right hand has no special meaning', 'a', 'Revelation 1:16,20 — "He had in his right hand seven stars... The seven stars are the angels of the seven churches." The right hand denotes power and favour throughout Scripture (Psalm 110:1; Isaiah 41:10).'),
('Revelation', 1, 'adults', 5, 'What does "I am he that liveth, and was dead; and, behold, I am alive for evermore" establish about Christ?', 'It is a declaration of Christ''s eternality, real death, and bodily resurrection — He possesses life inherently, genuinely died, and now lives permanently with authority over death and Hades', 'He is a created being who was revived', 'He never actually died', 'He is only alive symbolically', 'a', 'Revelation 1:18 — "I am he that liveth, and was dead; and, behold, I am alive for evermore, Amen; and have the keys of hell and of death." The present participle "the living one" (ho zōn) asserts essential, underived life.'),
('Revelation', 1, 'adults', 6, 'What is the threefold time structure John is told to write about?', '"The things which thou hast seen, and the things which are, and the things which shall be hereafter" — past vision (ch.1), present church age (ch.2-3), and future events (ch.4-22)', 'Only future events', 'Only past events', 'Only the present situation', 'a', 'Revelation 1:19 — "Write the things which thou hast seen, and the things which are, and the things which shall be hereafter." This verse provides the book''s interpretive outline: past, present, and future.'),
('Revelation', 1, 'adults', 7, 'How does the description of Christ in verses 13-16 draw upon Daniel 7 and 10?', 'The white hair echoes the Ancient of Days (Daniel 7:9), the bronze feet and mighty voice echo Daniel 10:6 — John applies divine attributes from both Daniel theophanies to the risen Christ, asserting His full deity', 'It only draws from Ezekiel', 'There are no Old Testament parallels', 'The description is entirely original', 'a', 'Revelation 1:13-16 — White hair (Daniel 7:9), eyes of fire and feet of brass (Daniel 10:6), voice of many waters (Ezekiel 43:2). John deliberately merges attributes of YHWH and the messianic Son of Man onto the risen Jesus.'),
('Revelation', 1, 'adults', 8, 'What does "the sharp twoedged sword" proceeding from Christ''s mouth represent?', 'The word of God — His authoritative, penetrating, and judging word that discerns and executes judgment (cf. Hebrews 4:12; Isaiah 49:2; Revelation 19:15)', 'A literal metal weapon', 'Roman military power', 'A decorative symbol', 'a', 'Revelation 1:16 — "Out of his mouth went a sharp twoedged sword." This imagery recurs at 2:12,16; 19:15,21, always representing Christ''s authoritative word of judgment (cf. Isaiah 49:2 — "He hath made my mouth like a sharp sword").');

-- ═══ Revelation Chapter 2 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Revelation', 2, 'kids', 1, 'What did Jesus tell the church of Ephesus they had left?', 'Their first love — they had stopped loving Jesus the way they did at the beginning', 'Their homes', 'Their money', 'Their pets', 'a', 'Revelation 2:4 — "Nevertheless I have somewhat against thee, because thou hast left thy first love."'),
('Revelation', 2, 'kids', 2, 'What did Jesus promise to those who overcome in Smyrna?', 'A crown of life — they would not be hurt by the second death', 'A bag of gold', 'A new house', 'A faster horse', 'a', 'Revelation 2:10-11 — "Be thou faithful unto death, and I will give thee a crown of life... He that overcometh shall not be hurt of the second death."'),
('Revelation', 2, 'kids', 3, 'What did Jesus say He had against the church in Thyatira?', 'They allowed a wicked woman called Jezebel to teach and lead God''s people into sin', 'They sang too loudly', 'They met on the wrong day', 'Their building was too small', 'a', 'Revelation 2:20 — "Notwithstanding I have a few things against thee, because thou sufferest that woman Jezebel, which calleth herself a prophetess, to teach and to seduce my servants."'),
-- Teens
('Revelation', 2, 'teens', 1, 'What does Jesus commend the church of Ephesus for, and what does He charge against them?', 'He commends their labour, patience, and rejection of false apostles, but charges them with leaving their first love', 'He has nothing good to say about them', 'He only commends their music', 'He praises their wealth', 'a', 'Revelation 2:2-4 — "I know thy works, and thy labour, and thy patience, and how thou canst not bear them which are evil: and thou hast tried them which say they are apostles, and are not... thou hast left thy first love."'),
('Revelation', 2, 'teens', 2, 'What is the condition of the church of Smyrna despite their suffering?', 'They are rich spiritually even though materially poor — Jesus has no criticism of them', 'They are both spiritually and materially wealthy', 'They are failing in every area', 'They are average in every way', 'a', 'Revelation 2:9 — "I know thy works, and tribulation, and poverty, (but thou art rich)." Smyrna is one of only two churches (with Philadelphia) that receives no rebuke.'),
('Revelation', 2, 'teens', 3, 'What problem existed in the church at Pergamos?', 'Some held the doctrine of Balaam (leading people into idolatry and fornication) and the doctrine of the Nicolaitanes', 'They had no problems at all', 'They were too generous', 'They prayed too much', 'a', 'Revelation 2:14-15 — "Thou hast there them that hold the doctrine of Balaam, who taught Balac to cast a stumblingblock... So hast thou also them that hold the doctrine of the Nicolaitanes."'),
('Revelation', 2, 'teens', 4, 'What promise does Jesus make to the overcomer in Pergamos?', 'He will give them hidden manna and a white stone with a new name written that no one knows except the receiver', 'A chariot of gold', 'A throne on earth', 'A large army', 'a', 'Revelation 2:17 — "To him that overcometh will I give to eat of the hidden manna, and will give him a white stone, and in the stone a new name written, which no man knoweth saving he that receiveth it."'),
('Revelation', 2, 'teens', 5, 'What does Jesus promise the overcomer in Thyatira?', 'Power over the nations and the morning star', 'A kingdom on earth immediately', 'Freedom from all work', 'Unlimited wealth', 'a', 'Revelation 2:26-28 — "And he that overcometh, and keepeth my works unto the end, to him will I give power over the nations... And I will give him the morning star."'),
-- Adults
('Revelation', 2, 'adults', 1, 'What pattern does each of the seven letters follow?', 'Address to the angel, a christological self-description drawn from chapter 1, commendation ("I know"), criticism ("I have against thee"), exhortation, a call to hear, and an overcomer promise — though Smyrna and Philadelphia lack criticism', 'They are random with no structure', 'Only three follow a pattern', 'The pattern is unique to each letter', 'a', 'Each letter follows a sevenfold pattern: (1) addressee, (2) Christ''s self-identification, (3) "I know," (4) praise, (5) blame, (6) "He that hath an ear," (7) overcomer promise. This literary consistency unifies the seven into a coherent corpus.'),
('Revelation', 2, 'adults', 2, 'What does "left thy first love" (Ephesus) mean theologically?', 'The church maintained doctrinal orthodoxy and moral vigilance but lost the passionate, wholehearted devotion to Christ that marked their conversion — orthodoxy without love becomes mere duty', 'They literally moved away from their first building', 'They stopped attending services', 'They lost their financial resources', 'a', 'Revelation 2:4-5 — "Thou hast left thy first love. Remember therefore from whence thou art fallen, and repent." The verb "left" (aphiēmi) suggests deliberate abandonment, not gradual drift — and the remedy is repentance, not merely trying harder.'),
('Revelation', 2, 'adults', 3, 'What is the "synagogue of Satan" referenced in the Smyrna letter?', 'Jewish opponents who claimed to be God''s people but whose persecution of Christians showed they were serving Satan''s purposes — a claim to covenant identity without covenant faithfulness', 'An actual building dedicated to Satan worship', 'A metaphor for Roman government', 'A group of Gentile pagans', 'a', 'Revelation 2:9 — "I know the blasphemy of them which say they are Jews, and are not, but are the synagogue of Satan." The phrase does not condemn all Jews but specifically those who claim covenant identity while persecuting the church.'),
('Revelation', 2, 'adults', 4, 'What is the significance of Pergamos being called "where Satan''s seat is"?', 'Pergamum housed the great altar of Zeus, a major centre of emperor worship, and the temple of Asklepios (with its serpent symbol) — making it the epicentre of pagan and imperial religion in Asia Minor', 'Satan literally sat on a throne there', 'It was a completely abandoned city', 'It had no religious significance', 'a', 'Revelation 2:13 — "I know thy works, and where thou dwellest, even where Satan''s seat is." The massive altar of Zeus (now in Berlin''s Pergamon Museum), the Asklepion, and the first provincial temple for emperor worship (29 BC) made Pergamum uniquely saturated with idolatry.'),
('Revelation', 2, 'adults', 5, 'How does the "doctrine of Balaam" function typologically?', 'As Balaam counselled Balak to entice Israel into idolatry and sexual immorality (Numbers 25:1-3; 31:16), some in Pergamos were similarly leading Christians into compromise with pagan feasts involving idol-meat and fornication', 'Balaam was a positive role model', 'The doctrine refers to charitable giving', 'It has no Old Testament connection', 'a', 'Revelation 2:14 — "The doctrine of Balaam, who taught Balac to cast a stumblingblock before the children of Israel, to eat things sacrificed unto idols, and to commit fornication." Balaam''s strategy was to corrupt what he could not curse (Numbers 22-25; 31:16).'),
('Revelation', 2, 'adults', 6, 'What does the "white stone" promised to Pergamos overcomers likely signify?', 'Multiple backgrounds converge: a white voting stone (acquittal), a victory token, or an admission tessera to a banquet — collectively signifying divine acquittal, victory, and intimate fellowship with Christ', 'A literal piece of marble', 'A building material', 'A weapon for battle', 'a', 'Revelation 2:17 — "I will give him a white stone, and in the stone a new name written." In Roman culture, white stones signified acquittal in court, victory in games, and admission to feasts. All three resonate with the overcomer''s reward.'),
('Revelation', 2, 'adults', 7, 'Who is "Jezebel" in the Thyatira letter?', 'A symbolic name (drawn from 1 Kings 16:31; 2 Kings 9:22) for a self-proclaimed prophetess in Thyatira who was leading Christians into idolatrous feasts and sexual immorality — her teaching likely accommodated trade-guild participation requiring pagan rituals', 'The literal Old Testament queen resurrected', 'An angel sent to test the church', 'A Roman government official', 'a', 'Revelation 2:20 — "That woman Jezebel, which calleth herself a prophetess, to teach and to seduce my servants to commit fornication." As OT Jezebel imported Baal worship into Israel, this figure imported pagan compromise into the church — likely through trade-guild feasts.'),
('Revelation', 2, 'adults', 8, 'What does "I will give him the morning star" (Thyatira) mean?', 'Christ Himself is the morning star (Revelation 22:16) — the promise is the gift of Christ Himself in fullest intimacy and glory; it may also echo the messianic Numbers 24:17 ("a Star out of Jacob")', 'A literal astronomical body', 'A decorative jewel', 'An earthly kingdom', 'a', 'Revelation 2:28 — "I will give him the morning star." Christ identifies Himself as "the bright and morning star" in 22:16. The overcomer receives the ultimate reward: Christ Himself in unmediated communion.');

-- ═══ Revelation Chapter 3 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Revelation', 3, 'kids', 1, 'What did Jesus say about the church in Sardis?', 'They had a name that they were alive, but they were really dead — He told them to wake up', 'They were the best church', 'They were very strong', 'They were the happiest church', 'a', 'Revelation 3:1 — "I know thy works, that thou hast a name that thou livest, and art dead."'),
('Revelation', 3, 'kids', 2, 'What did Jesus tell the church in Philadelphia He had set before them?', 'An open door that no man can shut', 'A locked gate', 'A wall to climb', 'A heavy burden', 'a', 'Revelation 3:8 — "Behold, I have set before thee an open door, and no man can shut it."'),
('Revelation', 3, 'kids', 3, 'What did Jesus say about the church in Laodicea?', 'They were neither hot nor cold — they were lukewarm, and it made Him want to spit them out', 'They were the hottest church', 'They were the coldest church', 'They were perfect', 'a', 'Revelation 3:15-16 — "I know thy works, that thou art neither cold nor hot... So then because thou art lukewarm, and neither cold nor hot, I will spue thee out of my mouth."'),
-- Teens
('Revelation', 3, 'teens', 1, 'What does Jesus promise those who overcome in Sardis?', 'They will be clothed in white raiment, their names will not be blotted out of the book of life, and Jesus will confess their names before His Father', 'A large mansion on earth', 'Earthly fame and recognition', 'Freedom from all problems', 'a', 'Revelation 3:5 — "He that overcometh, the same shall be clothed in white raiment; and I will not blot out his name out of the book of life, but I will confess his name before my Father, and before his angels."'),
('Revelation', 3, 'teens', 2, 'What key about Philadelphia''s identity does Jesus hold?', 'The key of David — He opens and no man shuts, and shuts and no man opens', 'The key to a treasure chest', 'The key to an earthly kingdom', 'A golden skeleton key', 'a', 'Revelation 3:7 — "These things saith he that is holy, he that is true, he that hath the key of David, he that openeth, and no man shutteth; and shutteth, and no man openeth."'),
('Revelation', 3, 'teens', 3, 'What does Jesus counsel the Laodiceans to buy from Him?', 'Gold tried in the fire, white raiment, and eyesalve — true spiritual riches, covering, and sight', 'Real gold and expensive clothes', 'Land and property', 'Swords and armour', 'a', 'Revelation 3:18 — "I counsel thee to buy of me gold tried in the fire, that thou mayest be rich; and white raiment, that thou mayest be clothed... and anoint thine eyes with eyesalve, that thou mayest see."'),
('Revelation', 3, 'teens', 4, 'What famous verse comes from the Laodicean letter about Jesus knocking?', '"Behold, I stand at the door, and knock: if any man hear my voice, and open the door, I will come in to him, and will sup with him, and he with me"', '"Knock and the door shall be opened"', '"Enter through the narrow gate"', '"The door was shut"', 'a', 'Revelation 3:20 — "Behold, I stand at the door, and knock: if any man hear my voice, and open the door, I will come in to him, and will sup with him, and he with me."'),
('Revelation', 3, 'teens', 5, 'What does Jesus promise the overcomer in Laodicea?', 'To sit with Him on His throne, just as He overcame and sat down with His Father on His throne', 'A new chariot', 'An earthly crown', 'A position in government', 'a', 'Revelation 3:21 — "To him that overcometh will I grant to sit with me in my throne, even as I also overcame, and am set down with my Father in his throne."'),
-- Adults
('Revelation', 3, 'adults', 1, 'What historical irony underlies the Sardis letter?', 'Sardis was twice captured by surprise (by Cyrus in 546 BC and Antiochus III in 214 BC) because its defenders failed to watch — Jesus tells this complacent church to "be watchful" (grēgoreō), echoing their city''s fatal historical negligence', 'Sardis was never conquered', 'Sardis was famous for its military vigilance', 'There is no historical allusion', 'a', 'Revelation 3:2-3 — "Be watchful... If therefore thou shalt not watch, I will come on thee as a thief." The acropolis of Sardis was considered impregnable, yet twice fell to enemies who climbed unguarded cliffs at night — a vivid warning to an unwatchful church.'),
('Revelation', 3, 'adults', 2, 'What does "the key of David" signify in the Philadelphia letter?', 'It alludes to Isaiah 22:22 where Eliakim received authority over David''s house — Christ holds supreme, exclusive authority over entry into the messianic kingdom; His decisions to open or shut are final and irreversible', 'It is a literal key to David''s tomb', 'It refers to a musical instrument', 'It symbolises the key to Jerusalem''s gates', 'a', 'Revelation 3:7 — "He that hath the key of David, he that openeth, and no man shutteth; and shutteth, and no man openeth." Isaiah 22:22 — Eliakim''s stewardship over David''s house is now christologically applied to Jesus'' ultimate authority over the kingdom.'),
('Revelation', 3, 'adults', 3, 'What does "I will keep thee from the hour of temptation" promise Philadelphia?', 'Protection during (or from) the coming period of worldwide testing — the preposition ek ("out of") suggests either preservation through the trial or removal before it; this is a key text in pretribulational, midtribulational, and posttribulational debates', 'A simple promise of easy life', 'Freedom from all personal struggles', 'Exemption from daily temptation', 'a', 'Revelation 3:10 — "Because thou hast kept the word of my patience, I also will keep thee from (ek) the hour of temptation, which shall come upon all the world, to try them that dwell upon the earth." The phrase "hour of temptation" denotes a specific eschatological period.'),
('Revelation', 3, 'adults', 4, 'How does the Laodicean context illuminate "neither cold nor hot"?', 'Laodicea''s water supply came via aqueduct from hot springs (Hierapolis) and cold springs (Colossae) — by arrival it was tepid and nauseating; both hot (therapeutic) and cold (refreshing) water were useful, but lukewarm was repulsive and useless', 'It refers to weather temperature', 'It describes their emotional state', 'It has no local significance', 'a', 'Revelation 3:15-16 — The city''s notorious lukewarm water supply, arriving tepid through long aqueducts, made the metaphor viscerally powerful. Unlike Hierapolis (hot medicinal springs) or Colossae (cold refreshing streams), Laodicea''s water was functionally useless.'),
('Revelation', 3, 'adults', 5, 'How do Laodicea''s three industries explain Christ''s threefold counsel?', 'Laodicea was famous for banking (gold), black wool textile production (clothing), and the Phrygian eye-powder (medical school) — Christ''s counsel to buy gold, white raiment, and eyesalve directly inverts their civic pride, exposing spiritual poverty despite material wealth', 'The three items are random', 'They have no local significance', 'Christ is recommending literal purchases', 'a', 'Revelation 3:17-18 — "Thou sayest, I am rich, and increased with goods, and have need of nothing; and knowest not that thou art wretched, and miserable, and poor, and blind, and naked." Each deficiency targets a source of Laodicean civic pride.'),
('Revelation', 3, 'adults', 6, 'What is significant about Christ standing outside the door in Revelation 3:20?', 'The risen Christ is depicted outside His own church — He must knock to be admitted to a church that bears His name but has effectively excluded Him; this is an invitation to individual believers within the lukewarm congregation', 'He is visiting a non-Christian home', 'It describes evangelistic outreach to pagans', 'Christ is locked inside trying to get out', 'a', 'Revelation 3:20 — "Behold, I stand at the door, and knock." Though often used evangelistically, the context is addressed to a church (v.14). Christ is outside the Laodicean congregation, seeking re-entry through individuals who respond.'),
('Revelation', 3, 'adults', 7, 'How does the overcomer promise escalate across the seven letters?', 'From tree of life (Ephesus) to the crown of life (Smyrna) to hidden manna (Pergamos) to the morning star (Thyatira) to white garments (Sardis) to a pillar in God''s temple (Philadelphia) to enthronement with Christ (Laodicea) — a climactic progression toward ultimate intimacy and authority', 'The promises are all identical', 'They decrease in significance', 'There is no progression', 'a', 'The seven overcomer promises form an ascending trajectory: eating from the tree of life (2:7), escaping the second death (2:11), receiving hidden manna and a new name (2:17), ruling nations (2:26-28), being in the book of life (3:5), becoming a permanent temple pillar (3:12), and sharing Christ''s throne (3:21).'),
('Revelation', 3, 'adults', 8, 'What does "as many as I love, I rebuke and chasten" reveal about the Laodicean letter?', 'Even the harshest words (spue thee out) come from love — Christ''s severe rebuke is not rejection but fatherly discipline (Proverbs 3:12), and the call to repent shows restoration is still possible', 'Christ has given up on them', 'The rebuke proves He does not love them', 'Chastening means final condemnation', 'a', 'Revelation 3:19 — "As many as I love, I rebuke and chasten: be zealous therefore, and repent." The Greek phileō (intimate love) + paideuō (train/discipline) echo Proverbs 3:12 and Hebrews 12:6, framing the severe warning within redemptive love.');

-- ═══ Revelation Chapter 4 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Revelation', 4, 'kids', 1, 'What did John see open in heaven?', 'A door was opened in heaven, and a voice like a trumpet told him to come up', 'A window in a wall', 'A gate made of wood', 'A ladder reaching down', 'a', 'Revelation 4:1 — "After this I looked, and, behold, a door was opened in heaven: and the first voice which I heard was as it were of a trumpet talking with me; which said, Come up hither."'),
('Revelation', 4, 'kids', 2, 'What did the four living creatures say day and night?', '"Holy, holy, holy, Lord God Almighty, which was, and is, and is to come"', '"We are hungry"', '"Please let us rest"', '"Send us home"', 'a', 'Revelation 4:8 — "And they rest not day and night, saying, Holy, holy, holy, Lord God Almighty, which was, and is, and is to come."'),
('Revelation', 4, 'kids', 3, 'What did the twenty-four elders do before God''s throne?', 'They fell down, worshipped, and cast their crowns before the throne', 'They sat quietly and did nothing', 'They asked for more crowns', 'They walked away', 'a', 'Revelation 4:10 — "The four and twenty elders fall down before him that sat on the throne, and worship him that liveth for ever and ever, and cast their crowns before the throne."'),
-- Teens
('Revelation', 4, 'teens', 1, 'What surrounded the throne that John saw?', 'A rainbow like an emerald, twenty-four elders in white with gold crowns, and lightning, thunderings, and voices proceeding from the throne', 'Only clouds', 'Just empty space', 'A wall of fire', 'a', 'Revelation 4:3-5 — "There was a rainbow round about the throne, in sight like unto an emerald... four and twenty elders sitting, clothed in white raiment; and they had on their heads crowns of gold... out of the throne proceeded lightnings and thunderings and voices."'),
('Revelation', 4, 'teens', 2, 'What do the four living creatures look like?', 'The first like a lion, the second like a calf, the third had a face like a man, and the fourth like a flying eagle — each had six wings and was full of eyes', 'Four identical beings', 'Four ordinary animals', 'Four men in white robes', 'a', 'Revelation 4:7-8 — "The first beast was like a lion, and the second beast like a calf, and the third beast had a face as a man, and the fourth beast was like a flying eagle. And the four beasts had each of them six wings about him; and they were full of eyes within."'),
('Revelation', 4, 'teens', 3, 'What is before the throne that is described as a sea of glass?', 'A sea of glass like unto crystal — a transparent, glassy expanse before God''s throne', 'An actual ocean with waves', 'A lake of fire', 'A river of blood', 'a', 'Revelation 4:6 — "And before the throne there was a sea of glass like unto crystal."'),
('Revelation', 4, 'teens', 4, 'Why do the elders say God is worthy to receive glory?', '"For thou hast created all things, and for thy pleasure they are and were created"', '"Because you are the richest being"', '"Because you are the oldest being"', '"Because you won a war"', 'a', 'Revelation 4:11 — "Thou art worthy, O Lord, to receive glory and honour and power: for thou hast created all things, and for thy pleasure they are and were created."'),
('Revelation', 4, 'teens', 5, 'What are the seven lamps of fire before the throne?', 'The seven Spirits of God', 'Seven ordinary torches', 'Seven candlesticks from the temple', 'Seven stars from the sky', 'a', 'Revelation 4:5 — "And there were seven lamps of fire burning before the throne, which are the seven Spirits of God."'),
-- Adults
('Revelation', 4, 'adults', 1, 'How does the throne-room vision of chapter 4 draw upon Isaiah 6 and Ezekiel 1?', 'The "Holy, holy, holy" trisagion echoes Isaiah 6:3, while the four living creatures with multiple faces echo Ezekiel 1:5-10 — John synthesises Israel''s two greatest throne-room visions into a single christological scene', 'It draws only from Genesis', 'There are no Old Testament parallels', 'It only echoes Daniel', 'a', 'Revelation 4:6-8 — The four living creatures combine features of Isaiah''s seraphim (six wings, trisagion) and Ezekiel''s cherubim (four faces — lion, ox, man, eagle). John creates a composite heavenly vision from Israel''s prophetic tradition.'),
('Revelation', 4, 'adults', 2, 'Who are the twenty-four elders most likely?', 'Representatives of the redeemed community — possibly the twelve patriarchs of Israel and twelve apostles combined, representing the complete people of God from both testaments, enthroned and crowned as priestly kings', 'Twenty-four literal angels', 'Twenty-four Roman emperors', 'Twenty-four Old Testament prophets', 'a', 'Revelation 4:4 — The number twenty-four (12 tribes + 12 apostles), white garments (priestly), golden crowns (royal), and thrones (judicial authority) suggest the full company of the redeemed. The twenty-four priestly courses (1 Chronicles 24:7-18) may also contribute.'),
('Revelation', 4, 'adults', 3, 'What does the "sea of glass like unto crystal" signify?', 'It evokes the firmament of Ezekiel 1:22 and the molten sea in Solomon''s temple (1 Kings 7:23) — symbolising God''s transcendent purity, unapproachable holiness, and the separation between Creator and creation, now stilled and calm', 'It is a literal frozen ocean', 'It has no symbolic meaning', 'It represents the Mediterranean Sea', 'a', 'Revelation 4:6 — "Before the throne there was a sea of glass like unto crystal." Unlike the turbulent sea representing chaos (Revelation 13:1; 21:1), this sea is glassy and still — chaos has been subdued before God''s throne.'),
('Revelation', 4, 'adults', 4, 'What is the theological significance of the elders casting their crowns before the throne?', 'It is an act of worship acknowledging that all authority, honour, and achievement derive from God — their crowns (stephanos — victory wreaths) are returned to their source, recognising that created glory is derivative', 'It is a meaningless ritual', 'They are disposing of unwanted items', 'They are being punished', 'a', 'Revelation 4:10-11 — The practice of casting crowns before a superior was known in the ancient world (e.g., before Roman emperors). Here it represents the ultimate acknowledgment that all created glory and authority originate in and belong to God.'),
('Revelation', 4, 'adults', 5, 'How does the "seven Spirits of God" relate to the Holy Spirit?', 'It is a symbolic representation of the Holy Spirit in His sevenfold fullness — drawing on Isaiah 11:2 (the seven attributes of the Spirit on the Messiah) and Zechariah 4:2-10 (seven lamps/eyes); seven signifies completeness', 'There are literally seven separate spirits', 'It refers to seven angels', 'It is a reference to seven human prophets', 'a', 'Revelation 4:5 — "Seven lamps of fire burning before the throne, which are the seven Spirits of God." cf. Revelation 1:4; 3:1; 5:6. The sevenfold Spirit echoes Isaiah 11:2 and symbolises the Holy Spirit''s perfect, complete operation.'),
('Revelation', 4, 'adults', 6, 'What does the phrase "which was, and is, and is to come" attribute to God?', 'Eternal self-existence across all time — past, present, and future — an expansion of the divine name YHWH ("I AM THAT I AM," Exodus 3:14) into a tripartite temporal formula asserting God''s sovereign lordship over all history', 'It describes a created being', 'It is a reference to an angel', 'It only describes past existence', 'a', 'Revelation 4:8 — "Holy, holy, holy, Lord God Almighty, which was, and is, and is to come." This threefold temporal formula (cf. 1:4,8) expands the Tetragrammaton (YHWH), declaring God''s sovereignty over every moment of time.'),
('Revelation', 4, 'adults', 7, 'How does chapter 4 establish the theological foundation for the judgments that follow?', 'By establishing God''s absolute sovereignty as Creator before depicting His acts as Judge — the One who made all things has the right to judge all things; creation theology grounds judgment theology', 'Judgment has no theological basis here', 'The chapter is unrelated to later events', 'It only describes past creation', 'a', 'Revelation 4:11 — "Thou hast created all things, and for thy pleasure they are and were created." Before the sealed scroll is opened (ch.5-6) and judgments commence, John establishes that the Judge is the Creator — His right to judge flows from His right as Maker.'),
('Revelation', 4, 'adults', 8, 'What is the relationship between the worship in chapter 4 and the worship in chapter 5?', 'Chapter 4 celebrates God as Creator ("thou hast created all things") while chapter 5 celebrates the Lamb as Redeemer ("thou wast slain") — together they present a comprehensive theology of worship grounded in creation and redemption', 'They are identical scenes repeated', 'Chapter 5 contradicts chapter 4', 'There is no connection between them', 'a', 'Chapter 4 ends with creation worship (4:11) and chapter 5 adds redemption worship (5:9-10), building to the cosmic doxology (5:13) where every creature worships both "him that sitteth upon the throne, and... the Lamb."');

-- ═══ Revelation Chapter 5 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Revelation', 5, 'kids', 1, 'Who was the only one worthy to open the scroll with seven seals?', 'The Lamb — Jesus Christ, the Lion of the tribe of Judah', 'The strongest angel', 'John the apostle', 'The twenty-four elders', 'a', 'Revelation 5:5 — "Behold, the Lion of the tribe of Juda, the Root of David, hath prevailed to open the book, and to loose the seven seals thereof."'),
('Revelation', 5, 'kids', 2, 'What did the Lamb look like?', 'A Lamb as though it had been slain, with seven horns and seven eyes', 'A large roaring lion', 'An ordinary white sheep', 'A mighty eagle', 'a', 'Revelation 5:6 — "And I beheld, and, lo, in the midst of the throne... stood a Lamb as it had been slain, having seven horns and seven eyes."'),
('Revelation', 5, 'kids', 3, 'What did everyone in heaven sing about the Lamb?', '"Thou art worthy... for thou wast slain, and hast redeemed us to God by thy blood"', '"You are a great warrior"', '"You are the smartest one"', '"You built the biggest temple"', 'a', 'Revelation 5:9 — "And they sung a new song, saying, Thou art worthy to take the book, and to open the seals thereof: for thou wast slain, and hast redeemed us to God by thy blood."'),
-- Teens
('Revelation', 5, 'teens', 1, 'Why did John weep when no one could open the scroll?', 'Because no one in heaven, earth, or under the earth was found worthy to open and read the book', 'Because he was homesick', 'Because he was hungry', 'Because the elders were unkind', 'a', 'Revelation 5:3-4 — "And no man in heaven, nor in earth, neither under the earth, was able to open the book, neither to look thereon. And I wept much, because no man was found worthy to open and to read the book."'),
('Revelation', 5, 'teens', 2, 'What do the golden vials full of odours represent?', 'The prayers of the saints', 'Perfume for the throne room', 'Incense for sale', 'Medicine for the sick', 'a', 'Revelation 5:8 — "Golden vials full of odours, which are the prayers of saints."'),
('Revelation', 5, 'teens', 3, 'What has the Lamb made the redeemed to be?', 'Kings and priests unto God, and they shall reign on the earth', 'Soldiers in an army', 'Servants without authority', 'Angels in heaven', 'a', 'Revelation 5:10 — "And hast made us unto our God kings and priests: and we shall reign on the earth."'),
('Revelation', 5, 'teens', 4, 'How many angels joined in the worship of the Lamb?', 'Ten thousand times ten thousand, and thousands of thousands', 'Only twelve', 'About one hundred', 'Nobody joined', 'a', 'Revelation 5:11 — "And I beheld, and I heard the voice of many angels round about the throne... and the number of them was ten thousand times ten thousand, and thousands of thousands."'),
('Revelation', 5, 'teens', 5, 'What seven things is the Lamb worthy to receive?', 'Power, riches, wisdom, strength, honour, glory, and blessing', 'Only power and strength', 'Only honour and glory', 'Only riches and wisdom', 'a', 'Revelation 5:12 — "Worthy is the Lamb that was slain to receive power, and riches, and wisdom, and strength, and honour, and glory, and blessing."'),
-- Adults
('Revelation', 5, 'adults', 1, 'What is the scroll sealed with seven seals, and what Old Testament background informs it?', 'It likely represents God''s comprehensive plan for judgment and redemption — drawing on Ezekiel 2:9-10 (a scroll written within and without) and Roman legal documents (sealed wills or title deeds requiring authorised opening)', 'A simple letter to John', 'A list of names only', 'A blank scroll', 'a', 'Revelation 5:1 — "A book written within and on the backside, sealed with seven seals." The dual-sided writing echoes Ezekiel 2:9-10. Roman testaments were sealed with seven witnesses'' seals, opened sequentially — suggesting God''s testament/inheritance for creation.'),
('Revelation', 5, 'adults', 2, 'What is the significance of John hearing "the Lion" but seeing "a Lamb"?', 'This is the hermeneutical key to Revelation — John is told to expect a conquering Lion (Messianic warrior) but sees a slain Lamb; the Messiah conquers precisely through sacrificial death, reinterpreting power through the cross', 'The Lion and Lamb are two different beings', 'It is an error in the text', 'The Lamb later becomes a Lion', 'a', 'Revelation 5:5-6 — The Lion of Judah (Genesis 49:9) and Root of David (Isaiah 11:1,10) are messianic titles of power, yet the actual figure is "a Lamb as it had been slain" — the cruciform reinterpretation of messianic victory that governs the entire book.'),
('Revelation', 5, 'adults', 3, 'What do the Lamb''s seven horns and seven eyes represent?', 'Seven horns symbolise complete (perfect) power, and seven eyes are the seven Spirits of God sent into all the earth — together representing omnipotence and omniscience through the Holy Spirit', 'Literal physical features', 'Decorative elements with no meaning', 'A sign of weakness', 'a', 'Revelation 5:6 — "Having seven horns and seven eyes, which are the seven Spirits of God sent forth into all the earth." Horns = power (Daniel 7:24; Psalm 75:10); eyes = knowledge/sight (Zechariah 4:10). Seven = completeness. The slain Lamb possesses total power and total knowledge.'),
('Revelation', 5, 'adults', 4, 'How does the "new song" in verse 9 function in the context of worship?', 'It celebrates a new redemptive act — as Old Testament "new songs" (Psalm 33:3; 96:1; 144:9; Isaiah 42:10) celebrated new acts of divine deliverance, this song celebrates the unprecedented act of redemption through the Lamb''s blood from every tribe, tongue, people, and nation', 'It is simply a fresh melody', 'It replaces all previous worship', 'It has no connection to Old Testament worship', 'a', 'Revelation 5:9 — "They sung a new song, saying, Thou art worthy... for thou wast slain, and hast redeemed us to God by thy blood out of every kindred, and tongue, and people, and nation." The "new song" tradition celebrates decisive divine interventions.'),
('Revelation', 5, 'adults', 5, 'What does the sevenfold ascription in verse 12 signify?', 'The seven attributes (power, riches, wisdom, strength, honour, glory, blessing) represent the complete and exhaustive ascription of all divine qualities to the Lamb — mirroring the sevenfold fullness given to God in 7:12', 'A random list of virtues', 'Only three are important', 'The number is coincidental', 'a', 'Revelation 5:12 — Seven attributes of divine worthiness parallel the sevenfold doxology to God in 7:12, placing the Lamb on equal footing with the One on the throne — an implicit affirmation of Christ''s full deity.'),
('Revelation', 5, 'adults', 6, 'How does verse 13 expand the scope of worship?', '"Every creature which is in heaven, and on the earth, and under the earth, and such as are in the sea" — worship expands in concentric circles from the four living creatures to the elders to the angelic myriads to all creation, achieving a cosmic doxology that encompasses every level of existence', 'Worship decreases in scope', 'Only heaven worships', 'Creation does not participate', 'a', 'Revelation 5:13 — The progressive expansion of worship (4:8 → 4:10-11 → 5:8-10 → 5:11-12 → 5:13) reaches its climax with every created being ascribing "Blessing, and honour, and glory, and power" to both God and the Lamb — a fourfold universal doxology.'),
('Revelation', 5, 'adults', 7, 'What does the Lamb''s worthiness to open the scroll establish about Christ''s role in history?', 'Only the crucified and risen Christ has the authority to execute God''s plan for history — His worthiness is grounded in His redemptive death ("thou wast slain"), making the cross the qualifying event for all eschatological judgment and consummation', 'Any angel could have opened it', 'The scroll opened itself', 'The scroll was never opened', 'a', 'Revelation 5:9 — The Lamb''s worthiness is explicitly grounded in His sacrificial death and its redemptive result. The sealed plan of God for creation''s future can only be enacted by the One who redeemed creation through His blood.'),
('Revelation', 5, 'adults', 8, 'How does the dual worship of God and the Lamb in 5:13-14 function christologically?', 'It places Christ alongside the Father as the co-recipient of worship from all creation — the same praise language used for the Creator (4:11) is used for the Lamb, constituting one of the strongest implicit affirmations of Christ''s deity in the New Testament', 'Only God receives worship in this passage', 'The Lamb is worshipped as a creature', 'This passage denies Christ''s deity', 'a', 'Revelation 5:13 — "Blessing, and honour, and glory, and power, be unto him that sitteth upon the throne, and unto the Lamb for ever and ever." The conjunction "and" places the Lamb alongside the Father as co-recipient of identical worship from all creation.');

-- ═══════════════ CHAPTERS 6–11 ═══════════════

-- ═══ Revelation Chapter 6 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Revelation', 6, 'kids', 1, 'What happened when the Lamb opened the first four seals?', 'Four horsemen came out — on a white horse, a red horse, a black horse, and a pale horse', 'Four angels appeared', 'Four trumpets sounded', 'Four stars fell from the sky', 'a', 'Revelation 6:1-8 — The four seals release the famous four horsemen of the Apocalypse, each riding a different coloured horse.'),
('Revelation', 6, 'kids', 2, 'What did the souls under the altar cry out?', '"How long, O Lord, holy and true, dost thou not judge and avenge our blood?"', '"Please let us leave"', '"We want to go home"', '"Give us food and water"', 'a', 'Revelation 6:10 — "And they cried with a loud voice, saying, How long, O Lord, holy and true, dost thou not judge and avenge our blood on them that dwell on the earth?"'),
('Revelation', 6, 'kids', 3, 'What happened when the sixth seal was opened?', 'A great earthquake, the sun became black, the moon became as blood, and stars fell from the sky', 'Nothing happened', 'It started raining', 'A rainbow appeared', 'a', 'Revelation 6:12-13 — "There was a great earthquake; and the sun became black as sackcloth of hair, and the moon became as blood; And the stars of heaven fell unto the earth."'),
-- Teens
('Revelation', 6, 'teens', 1, 'What do the four horsemen represent?', 'Conquest (white horse), war (red horse), famine (black horse), and death (pale horse)', 'Four seasons of the year', 'Four stages of life', 'Four types of weather', 'a', 'Revelation 6:2-8 — The white horse represents conquest, the red horse takes peace from the earth (war), the black horse carries scales (famine), and the pale horse is named Death with Hell following.'),
('Revelation', 6, 'teens', 2, 'What was given to the souls under the altar?', 'White robes, and they were told to rest for a little season until the number of martyrs was complete', 'Swords and shields', 'Food and drink', 'Permission to return to earth', 'a', 'Revelation 6:11 — "And white robes were given unto every one of them; and it was said unto them, that they should rest yet for a little season, until their fellowservants also and their brethren, that should be killed as they were, should be fulfilled."'),
('Revelation', 6, 'teens', 3, 'Who tried to hide from the Lamb''s wrath?', 'Kings, great men, rich men, chief captains, mighty men, bondmen, and free men — every class of people', 'Only the poor and weak', 'Only the soldiers', 'No one tried to hide', 'a', 'Revelation 6:15 — "The kings of the earth, and the great men, and the rich men, and the chief captains, and the mighty men, and every bondman, and every free man, hid themselves in the dens and in the rocks of the mountains."'),
('Revelation', 6, 'teens', 4, 'What did people say to the mountains and rocks?', '"Fall on us, and hide us from the face of him that sitteth on the throne, and from the wrath of the Lamb"', '"Protect us from the rain"', '"Give us gold and silver"', '"Open a path for us"', 'a', 'Revelation 6:16 — "And said to the mountains and rocks, Fall on us, and hide us from the face of him that sitteth on the throne, and from the wrath of the Lamb."'),
('Revelation', 6, 'teens', 5, 'What fearful question ends chapter 6?', '"For the great day of his wrath is come; and who shall be able to stand?"', '"When will the rain stop?"', '"Who will feed the horses?"', '"Where shall we go next?"', 'a', 'Revelation 6:17 — "For the great day of his wrath is come; and who shall be able to stand?"'),
-- Adults
('Revelation', 6, 'adults', 1, 'How does the first horseman (white horse) differ from interpretations of Christ in Revelation 19:11?', 'Though both ride white horses, the first horseman likely represents conquest/false peace (or Antichrist) — distinct from Christ in 19:11 who is named "Faithful and True"; the context of seals as judgments and the parallel with the other destructive horsemen suggest a counterfeit conqueror', 'They are identical figures', 'The white horse represents peace only', 'There is no connection between them', 'a', 'Revelation 6:2 — "A white horse: and he that sat on him had a bow; and a crown was given unto him: and he went forth conquering." Unlike Christ in 19:11 (a sword, many crowns, named Faithful), this rider has a bow and a single given crown — suggesting military conquest that initiates the judgments.'),
('Revelation', 6, 'adults', 2, 'How do the four horsemen relate to Jesus'' Olivet Discourse?', 'They correspond to the birth-pang signs of Matthew 24: false christs/conquest (v.5), wars (v.6), famines (v.7), and death/pestilence (Luke 21:11) — the seals dramatise Jesus'' own eschatological teaching', 'There is no parallel', 'The Olivet Discourse is about different events', 'Only one horseman has a parallel', 'a', 'Revelation 6:1-8 parallels Matthew 24:4-8: white horse = false messiahs, red horse = wars and rumours of wars, black horse = famines, pale horse = pestilence/death. The "beginning of sorrows" (Matthew 24:8) matches the progressive seal judgments.'),
('Revelation', 6, 'adults', 3, 'What does the fifth seal''s altar scene reveal about theodicy?', 'Martyrs cry "How long?" — acknowledging that divine justice delays but does not fail; they receive white robes (vindication) and are told God''s timing includes a determined number of martyrs before final retribution', 'God has abandoned the martyrs', 'The martyrs are punished', 'Justice is arbitrary', 'a', 'Revelation 6:9-11 — The altar echoes the brazen altar where blood was poured (Leviticus 4:7); the martyrs'' blood, like Abel''s, cries from the ground (Genesis 4:10). God''s response affirms both vindication (robes) and sovereign timing ("a little season").'),
('Revelation', 6, 'adults', 4, 'What Old Testament prophecies does the sixth seal cosmic disturbance echo?', 'Isaiah 34:4 (heavens rolled like a scroll), Joel 2:31 (sun to darkness, moon to blood), Isaiah 2:19 (hiding in rocks from the Lord''s terror) — the sixth seal synthesises prophetic Day of the Lord imagery', 'There are no Old Testament parallels', 'Only Psalm 23 is referenced', 'It echoes Genesis only', 'a', 'Revelation 6:12-17 — The cosmic signs draw from Isaiah 34:4; Joel 2:30-31; Isaiah 2:19-21; Hosea 10:8. This concentrated cluster of Day of the Lord imagery signals that the ultimate divine reckoning has arrived.'),
('Revelation', 6, 'adults', 5, 'What is the theological significance of "the wrath of the Lamb"?', 'It is a deliberate paradox — lambs are associated with meekness, not wrath; the combination asserts that the sacrificial Saviour is also the eschatological Judge, and those who reject His mercy will face His wrath', 'Lambs are naturally wrathful', 'It is a scribal error', 'Wrath contradicts the Lamb imagery', 'a', 'Revelation 6:16 — "The wrath of the Lamb." The oxymoron is theologically potent: the same Lamb whose blood redeems (5:9) also executes judgment. Mercy rejected becomes judgment intensified.'),
('Revelation', 6, 'adults', 6, 'How does the sevenfold social list in verse 15 function?', 'It encompasses all of humanity — from kings to slaves, seven categories covering the entire social spectrum — asserting that divine judgment is no respecter of persons; no social status provides exemption', 'It targets only the wealthy', 'It targets only the poor', 'It is a random selection', 'a', 'Revelation 6:15 — Seven categories: kings, great men, rich men, chief captains, mighty men, bondmen, free men. The seven-class list represents exhaustive totality — every human being regardless of rank, wealth, or power faces the Lamb''s wrath.'),
('Revelation', 6, 'adults', 7, 'What does the "scroll rolled together" sky signify?', 'It draws from Isaiah 34:4 — the dissolution of the present cosmic order; the sky peeling back like a scroll symbolises the removal of the barrier between heaven and earth, exposing creation to unmediated divine presence', 'A literal paper sky', 'A weather phenomenon', 'An astronomical observation', 'a', 'Revelation 6:14 — "The heaven departed as a scroll when it is rolled together." Isaiah 34:4 — "The heavens shall be rolled together as a scroll." The imagery suggests the visible universe peeling away to reveal the enthroned God behind it.'),
('Revelation', 6, 'adults', 8, 'How does the question "who shall be able to stand?" connect to the following chapter?', 'Chapter 7 answers this question by showing two groups who can stand: the 144,000 sealed Israelites and the innumerable multitude from all nations — those sealed by God and washed in the Lamb''s blood can endure divine wrath', 'Chapter 7 does not answer this question', 'No one can stand', 'The question is rhetorical with no answer', 'a', 'Revelation 6:17 — "Who shall be able to stand?" Chapter 7 provides the answer through two visions: the 144,000 sealed on earth (7:1-8) and the great multitude in heaven (7:9-17). God''s people are divinely protected through judgment.');

-- ═══ Revelation Chapter 7 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Revelation', 7, 'kids', 1, 'How many people from Israel were sealed with God''s special mark?', '144,000 — twelve thousand from each of the twelve tribes of Israel', '1,000', '100', '10,000', 'a', 'Revelation 7:4 — "And I heard the number of them which were sealed: and there were sealed an hundred and forty and four thousand of all the tribes of the children of Israel."'),
('Revelation', 7, 'kids', 2, 'After the 144,000, who else did John see?', 'A great multitude that no one could number, from every nation, standing before the throne in white robes', 'Only a few people', 'Nobody else', 'Just the twelve apostles', 'a', 'Revelation 7:9 — "After this I beheld, and, lo, a great multitude, which no man could number, of all nations, and kindreds, and people, and tongues, stood before the throne, and before the Lamb, clothed with white robes."'),
('Revelation', 7, 'kids', 3, 'What will God do for those who come through the great tribulation?', 'God will wipe away all tears from their eyes, and they will never be hungry or thirsty again', 'He will make them soldiers', 'He will send them back to earth', 'He will ask them to wait longer', 'a', 'Revelation 7:16-17 — "They shall hunger no more, neither thirst any more; neither shall the sun light on them, nor any heat. For the Lamb... shall lead them unto living fountains of waters: and God shall wipe away all tears from their eyes."'),
-- Teens
('Revelation', 7, 'teens', 1, 'What were the four angels holding back?', 'The four winds of the earth, so they would not blow on the earth, sea, or any tree', 'Four rivers', 'Four mountains', 'Four armies', 'a', 'Revelation 7:1 — "I saw four angels standing on the four corners of the earth, holding the four winds of the earth, that the wind should not blow on the earth, nor on the sea, nor on any tree."'),
('Revelation', 7, 'teens', 2, 'Why were the 144,000 sealed before the judgments continued?', 'To protect them — the seal of God on their foreheads marks them as belonging to God during the coming tribulation', 'To identify them for punishment', 'For decorative purposes', 'Because they were the most sinful', 'a', 'Revelation 7:3 — "Hurt not the earth, neither the sea, nor the trees, till we have sealed the servants of our God in their foreheads."'),
('Revelation', 7, 'teens', 3, 'What did the great multitude cry out?', '"Salvation to our God which sitteth upon the throne, and unto the Lamb"', '"Give us more food"', '"Let us go home"', '"We are tired of waiting"', 'a', 'Revelation 7:10 — "And cried with a loud voice, saying, Salvation to our God which sitteth upon the throne, and unto the Lamb."'),
('Revelation', 7, 'teens', 4, 'How did the great multitude make their robes white?', 'They washed them and made them white in the blood of the Lamb', 'They used soap and water', 'They bought new robes', 'An angel cleaned them', 'a', 'Revelation 7:14 — "These are they which came out of great tribulation, and have washed their robes, and made them white in the blood of the Lamb."'),
('Revelation', 7, 'teens', 5, 'What will the Lamb do for those who are before the throne?', 'He will feed them and lead them to living fountains of waters', 'He will give them swords', 'He will send them on missions', 'He will teach them to fight', 'a', 'Revelation 7:17 — "For the Lamb which is in the midst of the throne shall feed them, and shall lead them unto living fountains of waters: and God shall wipe away all tears from their eyes."'),
-- Adults
('Revelation', 7, 'adults', 1, 'What is the literary function of chapter 7 between the sixth and seventh seals?', 'It is an interlude (parenthesis) answering the question of 6:17 ("who shall be able to stand?") — showing two groups of the redeemed: the 144,000 sealed on earth and the innumerable multitude in heaven, providing assurance before the final seal', 'It is a digression with no purpose', 'It continues the seal sequence without pause', 'It belongs chronologically before chapter 6', 'a', 'Chapter 7 interrupts the seal sequence between the sixth and seventh seals, a pattern repeated between the sixth and seventh trumpets (10:1-11:14). These interludes provide pastoral reassurance amid judgment.'),
('Revelation', 7, 'adults', 2, 'Who are the 144,000 — literal Israel or symbolic church?', 'This is debated: (1) a literal remnant of ethnic Israel sealed for protection during the tribulation (cf. Romans 11:26), or (2) a symbolic number (12×12×1000) representing the complete church militant on earth. The tribal listing, though modified, supports an Israelite identification', 'They are 144,000 literal angels', 'They are randomly selected humans', 'They represent only Gentile believers', 'a', 'Revelation 7:4-8 — The number 12×12×1000 is clearly symbolic (completeness squared × fullness), but the tribal listing suggests ethnic Israel. Notably, Dan is omitted and Joseph replaces Ephraim — possibly due to Dan''s association with idolatry (Judges 18; 1 Kings 12:29).'),
('Revelation', 7, 'adults', 3, 'What is the significance of Dan''s omission from the tribal list?', 'Dan''s absence is likely due to the tribe''s association with idolatry (Judges 18:30; 1 Kings 12:29 — Jeroboam''s golden calf at Dan); early tradition (Irenaeus) associated Antichrist with Dan based on Genesis 49:17 and Jeremiah 8:16', 'It is a scribal error', 'Dan was too small to include', 'There is no significance', 'a', 'Revelation 7:5-8 — Dan is omitted while Manasseh (normally part of Joseph) is listed separately. The Testaments of the Twelve Patriarchs (Testament of Dan 5:6) predicted Dan would be led into idolatry — a tradition John likely knew.'),
('Revelation', 7, 'adults', 4, 'How does the innumerable multitude relate to the 144,000?', 'Using the Lion/Lamb pattern of chapter 5 (hearing one thing, seeing another), John hears a number (144,000) but sees an innumerable multitude — possibly the same group from two perspectives: earthly (numbered, sealed Israel) and heavenly (countless, victorious church)', 'They are completely unrelated groups', 'The multitude replaces the 144,000', 'The 144,000 become the multitude by dying', 'a', 'Revelation 7:4,9 — As John heard "Lion" but saw "Lamb" (5:5-6), he hears a precise number (144,000) but sees an uncountable multitude. This interpretive pattern suggests the same reality viewed from complementary angles.'),
('Revelation', 7, 'adults', 5, 'What does "washed their robes and made them white in the blood of the Lamb" mean theologically?', 'It is a paradox of grace — blood normally stains, but the Lamb''s blood cleanses; the martyrs'' purity comes not from their own suffering but from Christ''s atoning sacrifice applied to them', 'They literally washed clothes in blood', 'Their own suffering purified them', 'White robes were a dress code', 'a', 'Revelation 7:14 — "Washed their robes, and made them white in the blood of the Lamb." The paradox of cleansing through blood echoes 1 John 1:7 and Hebrews 9:14. Purity is entirely Christ''s achievement applied to believers.'),
('Revelation', 7, 'adults', 6, 'How does the promise in verses 15-17 draw on Isaiah and the Psalms?', 'It combines Isaiah 49:10 ("they shall not hunger nor thirst; neither shall the heat nor sun smite them"), Isaiah 25:8 ("God will wipe away tears"), and Psalm 23:1-2 ("He leadeth me beside the still waters") — projecting pastoral care into eschatological fulfilment', 'It has no Old Testament background', 'It quotes only Ecclesiastes', 'It draws from Greek philosophy', 'a', 'Revelation 7:16-17 — "They shall hunger no more, neither thirst any more" (Isaiah 49:10); "God shall wipe away all tears" (Isaiah 25:8); "lead them unto living fountains of waters" (Psalm 23:2). The promises of Israel''s prophets reach their ultimate fulfilment.'),
('Revelation', 7, 'adults', 7, 'What does the sealing of God''s servants echo from the Old Testament?', 'Ezekiel 9:4 — where a man marked the foreheads of those who grieved over Jerusalem''s sins before the slaughter of the unmarked; likewise, God''s seal protects His own before judgment falls', 'There is no Old Testament parallel', 'It echoes the mark of Cain only', 'It draws from Egyptian practices', 'a', 'Revelation 7:3 — "Sealed the servants of our God in their foreheads." Ezekiel 9:4 — "Set a mark upon the foreheads of the men that sigh and that cry for all the abominations." The Hebrew letter tav (mark) was written as a cross or X-shape in the ancient script.'),
('Revelation', 7, 'adults', 8, 'What is the theological significance of "the Lamb... shall feed them" in verse 17?', 'The slain Lamb becomes the Shepherd — a breathtaking role reversal where the sacrificial victim assumes the shepherd role (cf. Psalm 23; John 10:11; 1 Peter 5:4), combining sacrificial imagery with pastoral care for eternity', 'The Lamb is separate from the Shepherd', 'The Lamb has no authority', 'Feeding has only physical meaning', 'a', 'Revelation 7:17 — "For the Lamb which is in the midst of the throne shall feed them." The Lamb (sacrificial victim) shepherds (feeds, leads) the redeemed — merging John 10:11 ("the good shepherd giveth his life") with Psalm 23''s imagery of divine care.');

-- ═══ Revelation Chapter 8 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Revelation', 8, 'kids', 1, 'What happened when the seventh seal was opened?', 'There was silence in heaven for about half an hour', 'Loud music played', 'Everyone started singing', 'Thunder shook the ground', 'a', 'Revelation 8:1 — "And when he had opened the seventh seal, there was silence in heaven about the space of half an hour."'),
('Revelation', 8, 'kids', 2, 'How many angels were given trumpets?', 'Seven angels were given seven trumpets', 'Three angels', 'Twelve angels', 'One angel', 'a', 'Revelation 8:2 — "And I saw the seven angels which stood before God; and to them were given seven trumpets."'),
('Revelation', 8, 'kids', 3, 'What happened when the first trumpet sounded?', 'Hail and fire mixed with blood were thrown on the earth, and a third of the trees and all green grass burned up', 'It started raining softly', 'Flowers began to grow', 'Nothing happened', 'a', 'Revelation 8:7 — "The first angel sounded, and there followed hail and fire mingled with blood, and they were cast upon the earth: and the third part of trees was burnt up, and all green grass was burnt up."'),
-- Teens
('Revelation', 8, 'teens', 1, 'What did the angel do with the golden censer before the trumpet judgments?', 'He filled it with fire from the altar and threw it to the earth, causing thunder, lightning, voices, and an earthquake', 'He offered it as a gift to John', 'He placed it gently on the ground', 'He put it away in a box', 'a', 'Revelation 8:5 — "And the angel took the censer, and filled it with fire of the altar, and cast it into the earth: and there were voices, and thunderings, and lightnings, and an earthquake."'),
('Revelation', 8, 'teens', 2, 'What happened when the second trumpet sounded?', 'Something like a great mountain burning with fire was thrown into the sea — a third of the sea became blood, a third of sea creatures died, and a third of ships were destroyed', 'A gentle rain fell', 'The sea became calm', 'Fish multiplied in the ocean', 'a', 'Revelation 8:8-9 — "And the second angel sounded, and as it were a great mountain burning with fire was cast into the sea: and the third part of the sea became blood; And the third part of the creatures which were in the sea, and had life, died; and the third part of the ships were destroyed."'),
('Revelation', 8, 'teens', 3, 'What was the name of the star that fell when the third trumpet sounded?', 'Wormwood — it poisoned a third of the waters and many people died because the waters were made bitter', 'Morning Star', 'Bethlehem Star', 'North Star', 'a', 'Revelation 8:10-11 — "And the name of the star is called Wormwood: and the third part of the waters became wormwood; and many men died of the waters, because they were made bitter."'),
('Revelation', 8, 'teens', 4, 'What was struck when the fourth trumpet sounded?', 'A third of the sun, moon, and stars were darkened — a third of the day and night had no light', 'The entire earth was brightened', 'Only the moon was affected', 'Nothing visible happened', 'a', 'Revelation 8:12 — "And the fourth angel sounded, and the third part of the sun was smitten, and the third part of the moon, and the third part of the stars; so as the third part of them was darkened."'),
('Revelation', 8, 'teens', 5, 'What did the angel flying through heaven cry out?', '"Woe, woe, woe, to the inhabiters of the earth by reason of the other voices of the trumpet of the three angels, which are yet to sound!"', '"Peace on earth"', '"All is well"', '"Come up higher"', 'a', 'Revelation 8:13 — "And I beheld, and heard an angel flying through the midst of heaven, saying with a loud voice, Woe, woe, woe, to the inhabiters of the earth by reason of the other voices of the trumpet of the three angels, which are yet to sound!"'),
-- Adults
('Revelation', 8, 'adults', 1, 'What is the significance of the half-hour silence in heaven?', 'It creates dramatic anticipation — a solemn pause before the next series of judgments; it may echo Habakkuk 2:20 ("The LORD is in his holy temple: let all the earth keep silence before him") and Zephaniah 1:7 ("Hold thy peace at the presence of the Lord GOD")', 'It is insignificant', 'Heaven ran out of songs', 'Everyone fell asleep', 'a', 'Revelation 8:1 — The silence contrasts with the continuous worship of 4:8 and creates a dramatic caesura. In Jewish apocalyptic tradition, silence precedes divine action (cf. 4 Ezra 7:30; 2 Baruch 3:7). The half-hour is the hush before the storm of judgment.'),
('Revelation', 8, 'adults', 2, 'How does the incense-prayer-judgment sequence in verses 3-5 function?', 'The angel offers incense with the prayers of the saints on the golden altar — then hurls fire from that same altar to earth; the prayers of God''s persecuted people become the catalyst for divine judgment', 'Prayer and judgment are unconnected', 'The incense is purely decorative', 'The saints'' prayers are ineffective', 'a', 'Revelation 8:3-5 — The movement is upward (prayers ascend with incense) then downward (fire cast to earth). The martyrs'' prayer of 6:10 ("How long?") is answered: their prayers are the trigger mechanism for the trumpet judgments.'),
('Revelation', 8, 'adults', 3, 'How do the first four trumpets parallel the Egyptian plagues?', 'Hail and fire (first plague — Exodus 9:23-24), sea to blood (first plague — Exodus 7:20-21), bitter waters (cf. Marah — Exodus 15:23), and darkness (ninth plague — Exodus 10:21-23) — the trumpet judgments recapitulate the Exodus plagues on a cosmic scale', 'There are no parallels', 'They parallel Greek myths', 'Only one trumpet has a parallel', 'a', 'Revelation 8:7-12 — The first four trumpets echo Egypt''s plagues: hail mixed with fire and blood (cf. Exodus 9:23-24), waters becoming blood (cf. Exodus 7:20), bitter/poisoned water, and darkness (cf. Exodus 10:21-22). God''s new exodus judgment operates on cosmic scale.'),
('Revelation', 8, 'adults', 4, 'What is the significance of the repeated "third part" limitation?', 'It indicates partial, warning judgments — not yet total destruction; God limits the scope to one-third as merciful restraint, giving opportunity for repentance before the full and final bowls (ch.16) which affect totality', 'It is a random fraction', 'It means most of creation is affected', 'The fraction has no theological meaning', 'a', 'Revelation 8:7-12 — The "third part" recurs twelve times in this chapter. Unlike the bowl judgments (ch.16) which are total, the trumpets affect only one-third — judgments are intensifying but not yet complete, leaving room for repentance.'),
('Revelation', 8, 'adults', 5, 'What does "Wormwood" signify in biblical and ancient context?', 'Wormwood (Artemisia absinthium) is extremely bitter — in the Old Testament it symbolises the bitterness of divine judgment and apostasy (Jeremiah 9:15; 23:15; Lamentations 3:15,19; Amos 5:7); the star''s name signifies that fresh water becomes a source of death', 'It is a type of sweet herb', 'It has no symbolic meaning', 'It refers to a geographical location', 'a', 'Revelation 8:11 — "The name of the star is called Wormwood." Jeremiah 9:15 — "I will feed them, even this people, with wormwood, and give them water of gall to drink." Wormwood consistently symbolises the bitter consequences of sin and divine judgment.'),
('Revelation', 8, 'adults', 6, 'How does the darkening of celestial bodies (fourth trumpet) function eschatologically?', 'It echoes Joel 2:31 and Amos 8:9 — the darkening of sun, moon, and stars is classic Day of the Lord imagery signalling that the cosmic order itself is being disrupted as a prelude to God''s final intervention in history', 'It describes a natural eclipse', 'It has no prophetic significance', 'It only affects nighttime', 'a', 'Revelation 8:12 — The fourth trumpet reduces light by one-third. Joel 2:31 — "The sun shall be turned into darkness, and the moon into blood, before the great and the terrible day of the LORD come." Cosmic disruption signals divine judgment.'),
('Revelation', 8, 'adults', 7, 'What is the structural relationship between the seven seals, seven trumpets, and seven bowls?', 'The seventh seal contains the seven trumpets, and the seventh trumpet may contain the seven bowls — a telescoping or nesting structure where each final judgment opens into the next series, creating progressive intensification', 'They are three separate, parallel sequences', 'They describe the same events', 'The bowls come before the trumpets', 'a', 'The seventh seal opens to reveal the seven trumpets (8:1-2), and the seventh trumpet may similarly open to the seven bowls (11:15; 15:1). This telescoping structure creates escalating judgment: seals (quarter), trumpets (third), bowls (total).'),
('Revelation', 8, 'adults', 8, 'What does the triple "woe" of the flying angel signal?', 'The three woes correspond to the final three trumpets (fifth, sixth, seventh) — each progressively worse than the trumpet judgments already described; the shift from "woe" signals a transition from judgments on nature to judgments directly on humanity', 'It is a simple greeting', 'It has no structural significance', 'It refers to three historical events', 'a', 'Revelation 8:13 — "Woe, woe, woe." The first woe = fifth trumpet (9:1-12), the second woe = sixth trumpet (9:13-11:14), the third woe = seventh trumpet (11:15-19). The woes mark an escalation from ecological to demonic to cosmic judgment.');

-- ═══ Revelation Chapter 9 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Revelation', 9, 'kids', 1, 'What came out of the bottomless pit when the fifth trumpet sounded?', 'Locusts that looked like scorpions — they could hurt people but not kill them', 'Beautiful butterflies', 'Friendly birds', 'Golden coins', 'a', 'Revelation 9:3 — "And there came out of the smoke locusts upon the earth: and unto them was given power, as the scorpions of the earth have power."'),
('Revelation', 9, 'kids', 2, 'Who was the king of the locusts?', 'An angel of the bottomless pit named Abaddon (in Hebrew) and Apollyon (in Greek), which means Destroyer', 'A kind and gentle leader', 'A human king named Caesar', 'There was no leader', 'a', 'Revelation 9:11 — "And they had a king over them, which is the angel of the bottomless pit, whose name in the Hebrew tongue is Abaddon, but in the Greek tongue hath his name Apollyon."'),
('Revelation', 9, 'kids', 3, 'Even after all these terrible things, did the people repent?', 'No, they still did not repent of their sins — they kept worshipping idols', 'Yes, everyone immediately repented', 'Some repented right away', 'They all started praying to God', 'a', 'Revelation 9:20 — "And the rest of the men which were not killed by these plagues yet repented not of the works of their hands."'),
-- Teens
('Revelation', 9, 'teens', 1, 'How long were the locusts allowed to torment people?', 'Five months — and in those days people would seek death but not find it', 'One day', 'One year', 'Ten years', 'a', 'Revelation 9:5,6 — "And to them it was given that they should not kill them, but that they should be tormented five months... And in those days shall men seek death, and shall not find it; and shall desire to die, and death shall flee from them."'),
('Revelation', 9, 'teens', 2, 'What did the locusts look like?', 'Like horses prepared for battle, with crowns of gold, faces like men, hair like women, teeth like lions, and breastplates of iron', 'Like ordinary grasshoppers', 'Like small flies', 'Like butterflies', 'a', 'Revelation 9:7-9 — "The shapes of the locusts were like unto horses prepared unto battle; and on their heads were as it were crowns like gold, and their faces were as the faces of men. And they had hair as the hair of women, and their teeth were as the teeth of lions."'),
('Revelation', 9, 'teens', 3, 'What happened when the sixth trumpet sounded?', 'Four angels bound at the great river Euphrates were released to kill a third of mankind', 'A beautiful rainbow appeared', 'Peace came to the earth', 'The sun shone brighter', 'a', 'Revelation 9:13-15 — "Loose the four angels which are bound in the great river Euphrates. And the four angels were loosed, which were prepared for an hour, and a day, and a month, and a year, for to slay the third part of men."'),
('Revelation', 9, 'teens', 4, 'How large was the army that came with the sixth trumpet?', 'Two hundred thousand thousand (200 million) horsemen', 'One thousand', 'Ten thousand', 'One million', 'a', 'Revelation 9:16 — "And the number of the army of the horsemen were two hundred thousand thousand: and I heard the number of them."'),
('Revelation', 9, 'teens', 5, 'What sins did the survivors refuse to repent of?', 'Worshipping devils and idols of gold, silver, brass, stone, and wood — plus their murders, sorceries, fornication, and thefts', 'They had already repented of everything', 'They only committed small sins', 'They were all innocent', 'a', 'Revelation 9:20-21 — "Repented not of the works of their hands, that they should not worship devils, and idols of gold, and silver, and brass, and stone, and of wood... Neither repented they of their murders, nor of their sorceries, nor of their fornication, nor of their thefts."'),
-- Adults
('Revelation', 9, 'adults', 1, 'What is the "bottomless pit" (abyssos) in Jewish and biblical tradition?', 'The abyss is the prison of demonic entities — in Jewish tradition the place where fallen angels are confined (cf. Luke 8:31; 2 Peter 2:4; Jude 6); the key given to the fallen star signals divinely permitted demonic release for judgment purposes', 'It is a literal geographical hole', 'It is another name for heaven', 'It has no theological meaning', 'a', 'Revelation 9:1-2 — "A star fall from heaven unto the earth: and to him was given the key of the bottomless pit." The abyss (Hebrew tehom; Greek abyssos) is the cosmic prison of demonic forces, temporarily opened by divine permission for the fifth trumpet judgment.'),
('Revelation', 9, 'adults', 2, 'How does the locust plague draw on Joel 1-2?', 'Joel describes a devastating locust invasion as a Day of the Lord judgment — Revelation 9 demonises the imagery, transforming agricultural locusts into demonic creatures from the abyss; the "horses prepared unto battle" echoes Joel 2:4 directly', 'There is no connection to Joel', 'Joel describes literal locusts only', 'Revelation reverses Joel''s meaning', 'a', 'Revelation 9:7 — "The shapes of the locusts were like unto horses prepared unto battle" echoes Joel 2:4 — "The appearance of them is as the appearance of horses; and as horsemen, so shall they run." Joel''s earthly plague becomes Revelation''s demonic onslaught.'),
('Revelation', 9, 'adults', 3, 'What does the five-month torment period signify?', 'Five months corresponds to the natural lifespan of locusts (roughly May-September) — even in the supernatural realm, God sets temporal limits on demonic activity; the torment is severe but divinely bounded', 'It is a random number', 'It represents five years', 'It has no significance', 'a', 'Revelation 9:5,10 — The five-month period may reflect the actual locust season. More importantly, it demonstrates God''s sovereign control — even demonic torment operates within divinely prescribed limits (cf. Job 1:12; 2:6).'),
('Revelation', 9, 'adults', 4, 'What is the significance of the dual name "Abaddon/Apollyon"?', 'Abaddon (Hebrew: destruction/ruin — cf. Job 26:6; 28:22; Psalm 88:11; Proverbs 15:11) and Apollyon (Greek: destroyer) — the bilingual naming ensures both Jewish and Gentile readers understand this is the personification of destruction itself', 'The names are meaningless', 'They refer to two different beings', 'They are human names', 'a', 'Revelation 9:11 — Abaddon appears in Job 26:6; 28:22; Psalm 88:11; Proverbs 15:11 as a personification of the realm of destruction. The Greek Apollyon may also subtly counter claims of the god Apollo (whose symbol was the locust).'),
('Revelation', 9, 'adults', 5, 'What does the release of the four Euphrates angels signify?', 'The Euphrates was the eastern boundary of the promised land (Genesis 15:18) and Rome''s eastern frontier — its breaching signifies the invasion of destructive forces from beyond the borders; the four angels held in reserve were prepared for a precise divine appointment ("an hour, a day, a month, a year")', 'The Euphrates is unimportant', 'The angels are benevolent', 'It describes a natural flood', 'a', 'Revelation 9:14-15 — The Euphrates marked the boundary between civilisation and barbarian hordes (Parthian threat). The precision of the timing ("an hour, and a day, and a month, and a year") emphasises God''s exact sovereign scheduling of judgment.'),
('Revelation', 9, 'adults', 6, 'What does the 200-million-strong army represent?', 'An army of incomprehensible size — whether literal or symbolic (echoing the "countless" armies of Eastern invasion fears), it represents an overwhelming destructive force that kills one-third of humanity through fire, smoke, and brimstone', 'A precise count of a human army', 'A small skirmish force', 'A peaceful delegation', 'a', 'Revelation 9:16-18 — Two hundred million (literally "two myriads of myriads") exceeds any ancient army. The triple killing agents — fire, smoke, and brimstone — echo Sodom''s destruction (Genesis 19:24) and anticipate the lake of fire (20:10).'),
('Revelation', 9, 'adults', 7, 'What theological problem does the refusal to repent in verses 20-21 expose?', 'It demonstrates the hardness of the unregenerate heart — even the most severe divine judgments do not automatically produce repentance; humanity''s rebellion is so deep that catastrophic suffering alone cannot break it without divine grace', 'Judgment always leads to repentance', 'The survivors were innocent', 'Repentance was not expected', 'a', 'Revelation 9:20-21 — Despite one-third of humanity being killed, "the rest of the men... repented not." This echoes Pharaoh''s hardened heart during the Egyptian plagues and demonstrates that judgment without grace does not produce saving repentance.'),
('Revelation', 9, 'adults', 8, 'How does the catalogue of sins in verses 20-21 summarise human rebellion?', 'It covers both tables of the law: idolatry (violations of commandments 1-2 — worshipping devils and idols) and moral crimes (violations of commandments 6-10 — murders, sorceries/pharmakeia, fornication, thefts); humanity rebels against both God and neighbour', 'The list is random and insignificant', 'Only one sin is mentioned', 'These are minor infractions', 'a', 'Revelation 9:20-21 — The sin catalogue mirrors Exodus 20: idolatry (20:3-6), murder (20:13), sorcery (pharmakeia — drug-related occultism), fornication (20:14), theft (20:15). Humanity violates the entire moral law while refusing to repent.');

-- ═══ Revelation Chapter 10 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Revelation', 10, 'kids', 1, 'What did the mighty angel have in his hand?', 'A little book (scroll) that was open', 'A sword', 'A trumpet', 'A crown', 'a', 'Revelation 10:2 — "And he had in his hand a little book open."'),
('Revelation', 10, 'kids', 2, 'What did John do with the little book?', 'He ate it — it was sweet like honey in his mouth but made his belly bitter', 'He threw it away', 'He gave it to someone else', 'He hid it under a rock', 'a', 'Revelation 10:9-10 — "Take it, and eat it up; and it shall make thy belly bitter, but it shall be in thy mouth sweet as honey. And I took the little book... and ate it up; and it was in my mouth sweet as honey: and as soon as I had eaten it, my belly was bitter."'),
('Revelation', 10, 'kids', 3, 'What was John told he must do again?', 'Prophesy again before many peoples, nations, tongues, and kings', 'Go home and rest', 'Stop writing', 'Build a temple', 'a', 'Revelation 10:11 — "Thou must prophesy again before many peoples, and nations, and tongues, and kings."'),
-- Teens
('Revelation', 10, 'teens', 1, 'How is the mighty angel described?', 'Clothed with a cloud, a rainbow on his head, his face like the sun, and his feet like pillars of fire', 'Dressed in ordinary robes', 'Invisible and silent', 'Small and timid', 'a', 'Revelation 10:1 — "I saw another mighty angel come down from heaven, clothed with a cloud: and a rainbow was upon his head, and his face was as it were the sun, and his feet as pillars of fire."'),
('Revelation', 10, 'teens', 2, 'What did the seven thunders say?', 'John was about to write it down, but a voice from heaven told him to seal up what they said and not write it', 'They told John to run away', 'They gave the exact date of the end', 'They said nothing important', 'a', 'Revelation 10:3-4 — "Seven thunders uttered their voices... I was about to write: and I heard a voice from heaven saying unto me, Seal up those things which the seven thunders uttered, and write them not."'),
('Revelation', 10, 'teens', 3, 'What did the angel swear about time?', '"There should be time no longer" — when the seventh angel sounds, the mystery of God shall be finished', 'Time would go on forever unchanged', 'Time would reverse itself', 'A new calendar would begin', 'a', 'Revelation 10:6-7 — "That there should be time no longer: But in the days of the voice of the seventh angel, when he shall begin to sound, the mystery of God should be finished, as he hath declared to his servants the prophets."'),
('Revelation', 10, 'teens', 4, 'Why was the little book sweet in the mouth but bitter in the stomach?', 'God''s word is sweet to receive (like Psalm 119:103), but the message of coming judgment is bitter to digest and proclaim', 'It was made of actual honey and poison', 'John was allergic to paper', 'The angel tricked him', 'a', 'Revelation 10:9-10 — The sweetness echoes Psalm 119:103 ("How sweet are thy words unto my taste") and Ezekiel 3:3. The bitterness reflects the painful content of judgment prophecy that must be proclaimed.'),
('Revelation', 10, 'teens', 5, 'Where did the mighty angel place his feet?', 'His right foot on the sea and his left foot on the earth — claiming authority over all creation', 'Both feet on a mountain', 'Both feet in the sea', 'He was floating in the air', 'a', 'Revelation 10:2 — "And he set his right foot upon the sea, and his left foot on the earth." This stance symbolises universal dominion — the angel''s authority spans both land and sea, the entirety of the created order.'),
-- Adults
('Revelation', 10, 'adults', 1, 'How does John''s eating of the scroll parallel Ezekiel 2:8-3:3?', 'Both prophets are commanded to eat a scroll before prophesying — Ezekiel''s was sweet as honey (Ezekiel 3:3); John''s is initially sweet but becomes bitter, reflecting the bittersweet nature of prophetic ministry: sweet communion with God''s word, bitter proclamation of judgment', 'There is no parallel', 'Ezekiel ate a literal book', 'John refused to eat the scroll', 'a', 'Revelation 10:9-10 — "Eat it up... sweet as honey... belly was bitter." Cf. Ezekiel 2:8-3:3. John''s experience adds the bitter stomach (absent in Ezekiel), intensifying the cost of prophetic ministry in the escalating eschatological context.'),
('Revelation', 10, 'adults', 2, 'What is the "mystery of God" that will be finished when the seventh trumpet sounds?', 'God''s full redemptive plan — the mystery long declared through the prophets (cf. Romans 16:25-26; Ephesians 1:9-10; 3:4-6) that will reach its consummation: evil judged, creation renewed, God''s kingdom fully realised', 'A riddle with no solution', 'A minor theological detail', 'Something unrelated to previous prophecy', 'a', 'Revelation 10:7 — "The mystery of God should be finished, as he hath declared to his servants the prophets." The mystērion is God''s long-veiled plan for history, progressively revealed (Amos 3:7) and consummated at the seventh trumpet.'),
('Revelation', 10, 'adults', 3, 'Why are the seven thunders sealed rather than recorded?', 'It demonstrates that not all revelation is for public disclosure — God retains sovereign prerogatives over what is revealed; it also creates narrative tension and reminds readers that God''s purposes exceed what Scripture records (cf. 2 Corinthians 12:4; Deuteronomy 29:29)', 'John forgot what they said', 'The thunders were unintelligible', 'Sealing has no purpose', 'a', 'Revelation 10:4 — "Seal up those things which the seven thunders uttered, and write them not." Cf. Daniel 12:4,9 where sealing preserves content for a future time. Here, sealing permanently withholds content, underscoring divine sovereignty over revelation.'),
('Revelation', 10, 'adults', 4, 'What is the literary function of chapter 10 in the overall structure?', 'It is the second interlude (between the sixth and seventh trumpets, paralleling chapter 7''s interlude between the sixth and seventh seals) — recommissioning John for continued prophetic ministry before the final trumpet sounds', 'It continues the trumpet sequence without pause', 'It is misplaced', 'It has no structural significance', 'a', 'Like chapter 7, chapter 10 creates a narrative pause between the sixth and seventh elements of a series. The pattern (6 judgments → interlude → 7th judgment) builds suspense while providing theological reflection and prophetic recommissioning.'),
('Revelation', 10, 'adults', 5, 'How does the angel''s oath "by him that liveth for ever and ever, who created heaven and earth and sea" echo Daniel 12?', 'In Daniel 12:7, the man clothed in linen swears by Him who lives forever that the time will be "a time, times, and half a time"; Revelation 10:6 similarly swears by the eternal Creator but declares "time no longer" — the Danielic delay is reaching its consummation', 'There is no connection to Daniel', 'Daniel and Revelation contradict each other', 'The oath is meaningless', 'a', 'Revelation 10:5-6 — The angel raises his hand to heaven and swears (cf. Daniel 12:7). While Daniel''s angel set a future timeline ("time, times, half a time"), Revelation''s angel declares that delay is ending — the mystery will be completed.'),
('Revelation', 10, 'adults', 6, 'What does the angel''s stance on sea and land signify?', 'Universal authority and cosmic scope — the angel''s colossus-like posture claims dominion over the entire created order, signalling that the message concerns the whole earth, not just a local region', 'He needed to cool his feet', 'It has no symbolic meaning', 'He was looking for dry ground', 'a', 'Revelation 10:2,5 — The angel plants one foot on the sea and one on the earth, then raises his hand to heaven — connecting all three realms (heaven, earth, sea). This triad encompasses all creation (cf. Exodus 20:11; Psalm 146:6).'),
('Revelation', 10, 'adults', 7, 'What does "thou must prophesy again" commission John to do?', 'It recommissions John for the second half of Revelation — the visions from chapter 11 onward; the word "again" (palin) indicates that the preceding visions are complete and a new prophetic cycle addressing peoples, nations, tongues, and kings is beginning', 'John''s prophetic ministry is ending', 'He must repeat what he already wrote', 'He should stop writing', 'a', 'Revelation 10:11 — "Thou must prophesy again before many peoples, and nations, and tongues, and kings." This is a renewal of John''s prophetic commission (cf. Jeremiah 1:10; Ezekiel 2:3-4) for the next phase of visions.'),
('Revelation', 10, 'adults', 8, 'How does the "little book" (biblaridion) relate to the sealed scroll of chapter 5?', 'The diminutive form may indicate a portion or summary of the larger scroll — as seals are opened and trumpets sound, the content progressively unfolds; the open (already unsealed) little book suggests partially revealed content that John must now internalise and proclaim', 'They are completely unrelated documents', 'It is the same scroll unchanged', 'The little book replaces the larger scroll', 'a', 'Revelation 10:2 — The "little book open" (biblaridion ēneōgmenon) contrasts with the sealed scroll of 5:1. The scroll was sealed; this book is already open. It may represent the portion of divine revelation now being given to John for prophetic proclamation.');

-- ═══ Revelation Chapter 11 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Revelation', 11, 'kids', 1, 'What did God send two special witnesses to do?', 'Prophesy for 1,260 days, dressed in sackcloth', 'Build a new temple', 'Start a war', 'Sail across the sea', 'a', 'Revelation 11:3 — "And I will give power unto my two witnesses, and they shall prophesy a thousand two hundred and threescore days, clothed in sackcloth."'),
('Revelation', 11, 'kids', 2, 'What happened to the two witnesses after they finished their testimony?', 'The beast from the bottomless pit killed them, but after three and a half days God raised them back to life', 'They flew away to heaven', 'They hid in a cave', 'Nothing happened to them', 'a', 'Revelation 11:7,11 — "The beast that ascendeth out of the bottomless pit shall... kill them... And after three days and an half the Spirit of life from God entered into them, and they stood upon their feet."'),
('Revelation', 11, 'kids', 3, 'What happened when the seventh trumpet sounded?', 'Loud voices in heaven said, "The kingdoms of this world are become the kingdoms of our Lord, and of his Christ; and he shall reign for ever and ever"', 'Everything went quiet', 'It started raining', 'A new star appeared', 'a', 'Revelation 11:15 — "And the seventh angel sounded; and there were great voices in heaven, saying, The kingdoms of this world are become the kingdoms of our Lord, and of his Christ; and he shall reign for ever and ever."'),
-- Teens
('Revelation', 11, 'teens', 1, 'What powers did the two witnesses have?', 'Fire came from their mouths to devour enemies, they could shut the sky so it would not rain, turn water to blood, and strike the earth with plagues', 'They could fly and become invisible', 'They could read minds', 'They had no special powers', 'a', 'Revelation 11:5-6 — "If any man will hurt them, fire proceedeth out of their mouth, and devoureth their enemies... These have power to shut heaven, that it rain not... and have power over waters to turn them to blood, and to smite the earth with all plagues."'),
('Revelation', 11, 'teens', 2, 'What happened when the world saw the two witnesses rise from the dead?', 'Great fear fell on those who saw them, and a voice from heaven said "Come up hither" — they ascended to heaven in a cloud', 'People were happy and celebrated', 'Nobody noticed', 'The world ignored them', 'a', 'Revelation 11:11-12 — "And great fear fell upon them which saw them. And they heard a great voice from heaven saying unto them, Come up hither. And they ascended up to heaven in a cloud; and their enemies beheld them."'),
('Revelation', 11, 'teens', 3, 'What did the people of the world do when the two witnesses were killed?', 'They rejoiced, made merry, and sent gifts to one another because the two prophets had tormented them', 'They mourned and wept', 'They buried them with honours', 'They built monuments for them', 'a', 'Revelation 11:10 — "And they that dwell upon the earth shall rejoice over them, and make merry, and shall send gifts one to another; because these two prophets tormented them that dwelt on the earth."'),
('Revelation', 11, 'teens', 4, 'What happened after the witnesses ascended?', 'A great earthquake destroyed a tenth of the city and killed seven thousand people — the rest were afraid and gave glory to God', 'Nothing happened', 'The city was rebuilt immediately', 'Peace came over the land', 'a', 'Revelation 11:13 — "And the same hour was there a great earthquake, and the tenth part of the city fell, and in the earthquake were slain of men seven thousand: and the remnant were affrighted, and gave glory to the God of heaven."'),
('Revelation', 11, 'teens', 5, 'What did the twenty-four elders do when the seventh trumpet sounded?', 'They fell on their faces and worshipped God, saying He had taken His great power and begun to reign', 'They stood silently', 'They left the throne room', 'They asked for more time', 'a', 'Revelation 11:16-17 — "And the four and twenty elders, which sat before God on their seats, fell upon their faces, and worshipped God, Saying, We give thee thanks, O Lord God Almighty... because thou hast taken to thee thy great power, and hast reigned."'),
-- Adults
('Revelation', 11, 'adults', 1, 'What does the measuring of the temple in verses 1-2 signify?', 'Measuring symbolises divine protection and preservation (cf. Ezekiel 40-42; Zechariah 2:1-5) — the inner temple (naos) and worshippers are measured (preserved), while the outer court is given to the Gentiles for 42 months (exposed to persecution)', 'Literal architectural planning', 'Preparing for demolition', 'A census of the population', 'a', 'Revelation 11:1-2 — "Rise, and measure the temple of God, and the altar, and them that worship therein. But the court which is without the temple leave out... it is given unto the Gentiles." Measuring = claiming and protecting; excluding = exposing to tribulation.'),
('Revelation', 11, 'adults', 2, 'Who are the two witnesses most likely?', 'Their powers echo Moses (turning water to blood, plagues) and Elijah (shutting heaven from rain, fire from heaven) — they may be literal individuals, symbolic of the Law and Prophets witnessing in the end times, or representative of the witnessing church', 'Two unknown future politicians', 'Two literal olive trees', 'Two historical Roman emperors', 'a', 'Revelation 11:5-6 — Fire devouring enemies echoes Elijah (2 Kings 1:10-12); shutting heaven from rain echoes Elijah (1 Kings 17:1); water to blood and plagues echo Moses (Exodus 7:17; 9:14). The witnesses embody the combined testimony of the Law and Prophets.'),
('Revelation', 11, 'adults', 3, 'What is the significance of the 1,260 days / 42 months / three and a half years?', 'This period echoes Daniel 7:25 and 12:7 ("time, times, and half a time") — half of seven, symbolising a limited period of tribulation and persecution; it appears six times in Revelation (11:2,3; 12:6,14; 13:5) as the duration of evil''s permitted reign', 'It is a random number', 'It represents ten years', 'It has no Old Testament basis', 'a', 'Revelation 11:2-3 — 42 months = 1,260 days = 3½ years = "time, times, and half a time" (Daniel 7:25). This is half of seven (the number of completeness) — signifying a truncated, limited period of tribulation under divine sovereignty.'),
('Revelation', 11, 'adults', 4, 'What does the identification of the witnesses as "two olive trees and two candlesticks" draw from?', 'Zechariah 4:1-14 — where two olive trees (Joshua the high priest and Zerubbabel the governor) supply oil to the golden lampstand; they represent the anointed leaders who maintain God''s testimony through priestly and royal ministry', 'The imagery is original to Revelation', 'It draws from Greek mythology', 'It refers to two geographical locations', 'a', 'Revelation 11:4 — "These are the two olive trees, and the two candlesticks standing before the God of the earth." Zechariah 4:3,14 — "Two olive trees... These are the two anointed ones, that stand by the Lord of the whole earth."'),
('Revelation', 11, 'adults', 5, 'How does the witnesses'' death, public display, resurrection, and ascension parallel Christ''s experience?', 'They are killed, their bodies lie publicly for 3½ days (echoing Christ''s three days), their enemies celebrate, they are resurrected by God''s Spirit, and they ascend to heaven in a cloud — recapitulating Christ''s death-resurrection-ascension pattern as faithful witnesses', 'There is no parallel to Christ', 'The parallel is coincidental', 'Only the death parallels Christ', 'a', 'Revelation 11:7-12 — Death (v.7), public exposure (vv.8-9), resurrection (v.11), and ascension (v.12) mirror Jesus'' pattern. The 3½ days echo the three days in the tomb. The witnesses share Christ''s experience because they share His testimony.'),
('Revelation', 11, 'adults', 6, 'What does "the great city, which spiritually is called Sodom and Egypt, where also our Lord was crucified" identify?', 'Jerusalem — identified by the crucifixion reference but symbolically named Sodom (moral corruption — Isaiah 1:9-10) and Egypt (oppression of God''s people); the triple identification shows earthly Jerusalem has become a persecuting, corrupt anti-God city', 'Rome', 'Babylon', 'Athens', 'a', 'Revelation 11:8 — "Where also our Lord was crucified" identifies Jerusalem. The spiritual names Sodom (Genesis 19 — sexual immorality) and Egypt (Exodus — enslavement) characterise Jerusalem as a city of corruption and oppression — a shocking indictment.'),
('Revelation', 11, 'adults', 7, 'What does the seventh trumpet announce?', 'The cosmic transfer of sovereignty — "The kingdoms of this world are become the kingdoms of our Lord, and of his Christ; and he shall reign for ever and ever"; this is the proleptic announcement of God''s consummated reign, though the detailed fulfilment unfolds through the remaining chapters', 'Just another plague', 'The end of all prophecy', 'A minor event', 'a', 'Revelation 11:15 — The seventh trumpet is climactic: it announces the eschatological reality that all earthly authority is subsumed under God''s and Christ''s eternal reign. This is the consummation toward which all seals and trumpets have been building.'),
('Revelation', 11, 'adults', 8, 'What does the opening of the temple in heaven revealing the ark of the covenant signify?', 'God''s covenant faithfulness is vindicated — the ark, symbol of God''s covenant presence and mercy seat, appears in heaven at the moment of triumph; it declares that God has been faithful to every covenant promise despite earth''s rebellion', 'The ark was literally transported to heaven', 'It has no symbolic meaning', 'The temple was destroyed', 'a', 'Revelation 11:19 — "The temple of God was opened in heaven, and there was seen in his temple the ark of his testament." The earthly ark was lost (Jeremiah 3:16), but the heavenly reality it prefigured is revealed — God''s covenant faithfulness stands eternally.');
